#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return x - y;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        int *b = (int*)malloc(N * sizeof(int));
        int mn = 1000001;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
            b[i] = a[i];
            if (a[i] < mn) mn = a[i];
        }
        qsort(b, N, sizeof(int), cmp);
        int ok = 1;
        for (int i = 0; i < N; ++i) {
            if (a[i] != b[i] && b[i] % mn != 0) { ok = 0; break; }
        }
        printf(ok ? "YES\n" : "NO\n");
        free(a); free(b);
    }
    return 0;
}

