for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const a = new Array(N);
  let mn = Number.MAX_SAFE_INTEGER;
  for (let i = 0; i < N; ++i) {
    a[i] = Number(input[idx++]);
    if (a[i] < mn) mn = a[i];
  }
  const b = a.slice().sort((x, y) => x - y);
  let ok = true;
  for (let i = 0; i < N; ++i) {
    if (a[i] !== b[i] && b[i] % mn !== 0) { ok = false; break; }
  }
  output.push(ok ? 'YES' : 'NO');
}
